class FoodRatings {
    Map<String, String> foodToCuisine;
    Map<String, Integer> foodToRating;
    Map<String, TreeSet<Food>> cuisineToFood;

    public FoodRatings(String[] foods, String[] cuisines, int[] ratings) {
        foodToCuisine = new HashMap<>();
        foodToRating = new HashMap<>();
        cuisineToFood = new HashMap<>();

        for (int i = 0; i < foods.length; i++) {
            foodToCuisine.put(foods[i], cuisines[i]);
            foodToRating.put(foods[i], ratings[i]);
            if (!cuisineToFood.containsKey(cuisines[i])) {
                cuisineToFood.put(cuisines[i], new TreeSet<>((a, b) -> a.rating == b.rating ? a.name.compareTo(b.name) : b.rating - a.rating));
            }
            cuisineToFood.get(cuisines[i]).add(new Food(foods[i], ratings[i]));
        }
    }

    public void changeRating(String food, int newRating) {
        String cuisine = foodToCuisine.get(food);
        int oldRating = foodToRating.get(food);
        cuisineToFood.get(cuisine).remove(new Food(food, oldRating));
        cuisineToFood.get(cuisine).add(new Food(food, newRating));
        foodToRating.put(food, newRating);
    }

    public String highestRated(String cuisine) {
        return cuisineToFood.get(cuisine).first().name;
    }

    class Food {
        String name;
        int rating;

        public Food(String name, int rating) {
            this.name = name;
            this.rating = rating;
        }
    }
}
